pub fn swap_textures(&mut self) {
        self.adaptive_lut.swap();
    }
pub fn load_segment(
        &mut self,
        base_luts_flat: &[f32],
        base_boundaries: &[f32],
        hsl_data: (&[f32], &[f32], &[f32], &[f32]),
    ) -> Result<(), GpuError> {
        self.adaptive_lut.load_segment(
            &self.device, base_luts_flat, base_boundaries, hsl_data,
        )
    }
